command:
mkdir -p space .claude-tdd-pro/space && printf 'collected:
  - {id: space-perf-rubric-pass-rate, value: 0.95, prev: 0.80}
  - {id: space-friction-suppressions, value: 50, prev: 10}
' > .claude-tdd-pro/space/collected.yaml && printf 'metrics:
  - {id: space-perf-rubric-pass-rate, dimension: performance}
  - {id: space-friction-suppressions, dimension: efficiency_and_flow}
' > space/metrics.yaml && printf 'dimensions: {performance: {enabled: true}, efficiency_and_flow: {enabled: true}}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --collected .claude-tdd-pro/space/collected.yaml --config space/config.yaml 2>out.txt && grep -q 'counter-goodhart' out.txt && grep -q 'pass_rate_up_with_suppression_up' out.txt && echo ok 1>&2
